import swaggerAutoGen from "swagger-autogen";

const doc = {
  info: {
    title: "Stateless Auth API",
    description: "Stateless Auth API",
    version: "1.0.0"
  },
  host: `localhost:3000`,
  schemes: ["http"]
};

const outputFile = "./src/docs/swagger.json";
const endpointsFiles = ["./src/routes/*.ts"];

swaggerAutoGen(outputFile, endpointsFiles, doc);

import { Config, defineConfig } from "drizzle-kit";

import env from "./src/configs/env";

export default defineConfig({
  out: "./src/drizzle/migrations",
  schema: "./src/drizzle/index.ts",
  dialect: "mysql",
  dbCredentials: {
    url: env.DATABASE_URL!
  },
  verbose: true,
  strict: true
}) satisfies Config;

import app from "./app";
import env from "./configs/env";
import { connectRedis } from "./configs/redis";
import { logger } from "./utils/logger";
import { configureGracefulShutdown } from "./utils/shutdown";

const port = env.PORT || 9000;

connectRedis();

const server = app.listen(port, () => {
  logger.info(`[server]: Server is running at http://localhost:${port}`);
  logger.info(`[server]: Environment: ${env.NODE_ENV}`);
  logger.info(
    `[server]: Swagger docs are available at http://localhost:${port}/api/docs`
  );
});

configureGracefulShutdown(server);

import express, { Express, Request, Response } from "express";
import cors from "cors";
import helmet from "helmet";
import cookieParser from "cookie-parser";
import morgan from "morgan";
import { notFoundHandler } from "./middlewares/not-found-handler";
import { errorHandler } from "./middlewares/error-handler";
import Routes from "./routes/index";
import { startRefreshTokenCleanupJob } from "./cron/cleanup-refresh-tokens.cron";
import swaggerUi from "swagger-ui-express";
import swaggerDocument from "./docs/swagger.json";
import { rateLimiter } from "./middlewares/rate-limiter";
import sourceMapSupport from "source-map-support";
sourceMapSupport.install();

const app: Express = express();

app.use(express.json());
app.use(express.urlencoded({ extended: true }));
app.use(
  cors({
    origin: "*",
    credentials: true
  })
);
app.use(helmet());
app.use(cookieParser());
app.use(morgan(process.env.NODE_ENV === "development" ? "dev" : "combined"));

// Routes

app.get("/", (req: Request, res: Response) => {
  res.redirect("/api/v1/health");
});

app.use("/api", Routes);

app.use("/api/docs", swaggerUi.serve, swaggerUi.setup(swaggerDocument));
startRefreshTokenCleanupJob();

app.get(["/docs-json", "/api-docs-json"], (req: Request, res: Response) => {
  res.json(swaggerDocument);
});

app.use(rateLimiter);

// Not found handler (should be after routes)
app.use(notFoundHandler);

// Global error handler (should be last)
app.use(errorHandler);

export default app;

import * as z from "zod";

export const nameSchema = z
  .string({ error: "Name must be a string" })
  .trim()
  .min(3, {
    message: "Name must be at least 3 characters long"
  })
  .max(50, {
    message: "Name must be at most 50 characters long"
  });

export const passwordSchema = z
  .string({ error: "Password must be a string" })
  .trim()
  .min(6, {
    message: "Password must be at least 6 characters long"
  })
  .max(80, {
    message: "Password must be at most 80 characters long"
  });

export const emailSchema = z
  .email({ message: "Please enter a valid email address." })
  .max(100, { message: "Email must be no more than 100 characters." });

export const roleSchema = z
  .enum(["user", "admin"], {
    error: "Role must be either applicant, recruiter, or admin"
  })
  .default("user");

export const SigninSchema = z.object({
  email: emailSchema,
  password: z.string({ error: "Password must be a string" }).trim().min(1, {
    message: "Password is required"
  })
});

export const SignupSchema = z.object({
  name: nameSchema,
  email: emailSchema,
  password: passwordSchema,
  role: roleSchema
});

export const VerifyOtpSchema = z.object({
  code: z.string().min(6, "Please enter a valid OTP"),
  email: emailSchema
});

export const ResetPasswordSchema = z.object({
  email: emailSchema,
  newPassword: passwordSchema
});

export const ChangePasswordSchema = z.object({
  oldPassword: z.string({ error: "Password must be a string" }).min(1, {
    message: "Old password is required"
  }),
  newPassword: passwordSchema
});

export const UpdateProfileSchema = z.object({
  name: nameSchema.optional(),
  avatar: z.string().optional()
});

export const GoogleSigninSchema = z.object({
  name: nameSchema,
  email: emailSchema,
  provider: z.enum(["google", "github"]).default("google"),
  providerId: z.string({ error: "Provider id must be a string" }).min(1, {
    message: "Provider id is required"
  }),
  avatar: z.string().optional(),
  isEmailVerified: z.boolean().default(false)
});

export const DeleteAccountSchema = z.object({
  userId: z.number().min(1, {
    message: "User id is required"
  }),
  type: z
    .enum(["soft", "hard"], { error: "Type must be either soft or hard" })
    .default("soft")
});

export type SignupUserType = z.infer<typeof SignupSchema>;
export type SigninUserType = z.infer<typeof SigninSchema>;
export type ResetPasswordType = z.infer<typeof ResetPasswordSchema>;
export type ChangePasswordType = z.infer<typeof ChangePasswordSchema>;
export type UpdateProfileType = z.infer<typeof UpdateProfileSchema>;
export type GoogleSigninType = z.infer<typeof GoogleSigninSchema>;
export type DeleteAccountType = z.infer<typeof DeleteAccountSchema>;

export type VerifyOtpType = z.infer<typeof VerifyOtpSchema>;

import { Server } from "http";
import { logger } from "./logger";

export const configureGracefulShutdown = (server: Server) => {
  const signals = ["SIGTERM", "SIGINT"];

  signals.forEach(signal => {
    process.on(signal, () => {
      logger.info(`\n${signal} signal received. Shutting down gracefully...`);

      server.close(err => {
        if (err) {
          logger.error(err, "Error during server close");
          process.exit(1);
        }

        logger.info("HTTP server closed.");
        process.exit(0);
      });

      // Force shutdown after 10 seconds
      setTimeout(() => {
        logger.error(
          "Could not close connections in time, forcefully shutting down"
        );
        process.exit(1);
      }, 10000);
    });
  });
};

import env from "../configs/env";
import { getTransporter } from "../configs/nodemailer";
import { ApiError } from "./api-error";
import { renderEmailTemplates } from "./render-template";

type sendMail = {
  from?: string;
  subject: string;
  data: Record<string, any>;
  email: string;
  templateName: string;
};

export async function sendEmail({
  from,
  email,
  subject,
  data,
  templateName
}: sendMail) {
  const transporter = getTransporter();

  const html = await renderEmailTemplates(templateName, data);
  return transporter
    .sendMail({
      from: from || `<${env.EMAIL_FROM}>`,
      to: email,
      subject,
      html
    })
    .catch(err => {
      throw ApiError.badRequest("Failed to send email");
    });
}

import ejs from "ejs";
import path from "node:path";

export async function renderEmailTemplates(
  templateName: string,
  data: Record<string, any>
) {
  const templatePath = path.join(
    process.cwd(),
    "src",
    `email-templates`,
    `${templateName}.ejs`
  );
  return ejs.renderFile(templatePath, data);
}

import pino from "pino";
