  next: NextFunction
) => {
  throw ApiError.notFound(`Route ${req.method} ${req.originalUrl} not found`);
};

import { Request, Response, NextFunction } from "express";
import env from "../configs/env";

import { logger } from "../utils/logger";
import { ApiError } from "../utils/api-error";

export const errorHandler = (
  err: Error,
  req: Request,
  res: Response,
  next: NextFunction
) => {
  if (res.headersSent) {
    return next(err);
  }
  let statusCode = 500;
  let message = "Internal server error";
  let errors: unknown;

  if (err instanceof ApiError) {
    statusCode = err.statusCode;
    message = err.message;
    errors = err.errors;
  }

  logger.error(
    err,
    `Error: ${message} | Status: ${statusCode} | Path: ${req.method} ${req.originalUrl}`
  );

  const response = {
    success: false,
    message,
    statusCode,
    ...(errors !== undefined && { errors }),
    ...(env.NODE_ENV === "development" && { stack: err.stack })
  };

  res.status(statusCode).json(response);
};

import crypto from "node:crypto";

export function generateOTP(length: number = 6, ttlMinutes: number = 5) {
  const code = crypto
    .randomInt(0, Math.pow(10, length))
    .toString()
    .padStart(length, "0");

  const hashCode = crypto
    .createHash("sha256")
    .update(String(code))
    .digest("hex");

  const expiresAt = new Date(Date.now() + ttlMinutes * 60 * 1000).toISOString();

  return { code, hashCode, expiresAt };
}

export function generateHashedToken(token: string): string {
  return crypto.createHash("sha256").update(String(token)).digest("hex");
}

export function generateSecureToken(length: number = 32): string {
  return crypto.randomBytes(length).toString("hex");
}

export function verifyHashedToken(token: string, hashedToken: string): boolean {
  return (
    crypto.createHash("sha256").update(String(token)).digest("hex") ===
    hashedToken
  );
}

export function generateTokenAndHashedToken(id: string) {
  const cryptoSecret = process.env.CRYPTO_SECRET! || "secret";
  const token = crypto
    .createHmac("sha256", cryptoSecret)
    .update(String(id))
    .digest("hex");

  const hashedToken = crypto
    .createHash("sha256")
    .update(String(token))
    .digest("hex");
  return { token, hashedToken };
}

export function generateUUID(): string {
  return crypto.randomUUID();
}

import { Response } from "express";
import { ACCESS_TOKEN_EXPIRY, REFRESH_TOKEN_EXPIRY } from "../constants/auth";
import env from "../configs/env";

const isProduction = env.NODE_ENV === "production";

export const COOKIE_OPTIONS = {
  httpOnly: true,
  secure: isProduction,
  sameSite: isProduction ? ("none" as const) : ("lax" as const),
  path: "/"
};

export function setAuthCookies(
  res: Response,
  accessToken: string,
  refreshToken: string
) {
  setCookies(res, [
    {
      cookie: "accessToken",
      value: accessToken,
      maxAge: ACCESS_TOKEN_EXPIRY
    },
    {
      cookie: "refreshToken",
      value: refreshToken,
      maxAge: REFRESH_TOKEN_EXPIRY
    }
  ]);
}

export function clearAuthCookies(res: Response) {
  res.clearCookie("accessToken", COOKIE_OPTIONS);
  res.clearCookie("refreshToken", COOKIE_OPTIONS);
}

export function clearCookie(res: Response, cookie: string = "sid") {
  res.clearCookie(cookie, COOKIE_OPTIONS);
}

type Cookie = {
  cookie: string;
  value: string;
  maxAge: number;
};

export function setCookies(res: Response, cookies: Cookie[]) {
  cookies.forEach(({ cookie, value, maxAge }) => {
    res.cookie(cookie, value, {
      ...COOKIE_OPTIONS,
      maxAge
    });
  });
}

import argon2 from "argon2";

export async function hashPassword(password: string): Promise<string> {
  return argon2.hash(password);
}

export async function verifyPassword(
  password: string,
  hash: string
): Promise<boolean> {
  return argon2.verify(hash, password);
}

