import cron from "node-cron";
import { lt, or, eq } from "drizzle-orm";
import { refreshTokens } from "../drizzle";
import db from "../shared/configs/db";
import { logger } from "../shared/utils/logger";

export function startRefreshTokenCleanupJob() {
  cron.schedule(
    "0 2 * * *", // daily at 2 am
    async () => {
      try {
        const now = new Date();

        const [result] = await db
          .delete(refreshTokens)
          .where(
            or(
              lt(refreshTokens.expiresAt, now),
              eq(refreshTokens.isRevoked, true)
            )
          );

        logger.info(
          `Refresh token cleanup completed. Deleted ${result.affectedRows} records`
        );
      } catch (error) {
        logger.error(error, "Refresh token cleanup failed");
      }
    },
    {
      timezone: "Asia/Kathmandu"
    }
  );
}

import { Server } from "http";
import { logger } from "./logger";

export const configureGracefulShutdown = (server: Server) => {
  const signals = ["SIGTERM", "SIGINT"];

  signals.forEach(signal => {
    process.on(signal, () => {
      logger.info(`\n${signal} signal received. Shutting down gracefully...`);

      server.close(err => {
        if (err) {
          logger.error(err, "Error during server close");
          process.exit(1);
        }

        logger.info("HTTP server closed.");
        process.exit(0);
      });

      // Force shutdown after 10 seconds
      setTimeout(() => {
        logger.error(
          "Could not close connections in time, forcefully shutting down"
        );
        process.exit(1);
      }, 10000);
    });
  });
};

import env from "../configs/env";
import { getTransporter } from "../configs/nodemailer";
import { ApiError } from "../utils/api-error";
import { renderEmailTemplates } from "./render-template";

type sendMail = {
  from?: string;
  subject: string;
  data: Record<string, any>;
  email: string;
  templateName: string;
};

export async function sendEmail({
  from,
  email,
  subject,
  data,
  templateName
}: sendMail) {
  const transporter = getTransporter();

  const html = await renderEmailTemplates(templateName, data);
  return transporter
    .sendMail({
      from: from || `<${env.EMAIL_FROM}>`,
      to: email,
      subject,
      html
    })
    .catch(err => {
      throw ApiError.badRequest("Failed to send email");
    });
}

import ejs from "ejs";
import path from "node:path";

export async function renderEmailTemplates(
  templateName: string,
  data: Record<string, any>
) {
  const templatePath = path.join(
    process.cwd(),
    "src",
    `email-templates`,
    `${templateName}.ejs`
  );
  return ejs.renderFile(templatePath, data);
}

